const month = new Date().getMonth() + 1;
const monthNames = ['January','February','March','April','May','June','July','August','September','October','November','December'];
const monthName = monthNames[month - 1];

const seasonalContent = {
  1: { season: 'Winter', tip: 'Avoid walking on frozen grass -- it damages the crown. Plan your spring lawn care now for early booking discounts.', upsell: 'Snow Removal' },
  2: { season: 'Late Winter', tip: 'Start planning spring cleanup. Test your soil pH -- we can help interpret results and recommend amendments.', upsell: 'Spring Cleanup' },
  3: { season: 'Early Spring', tip: 'Time for spring cleanup! Remove debris and thatch before new growth starts. Early fertilization sets up success.', upsell: 'Fertilization' },
  4: { season: 'Spring', tip: 'Begin mowing at 3-3.5 inches. Don\'t cut more than 1/3 of blade height. Aerate compacted areas now.', upsell: 'Aeration & Overseeding' },
  5: { season: 'Late Spring', tip: 'Apply pre-emergent herbicide before crabgrass germinates. Water deeply but infrequently -- 1 inch per week.', upsell: 'Herbicide Treatment' },
  6: { season: 'Early Summer', tip: 'Raise mower height to 4 inches during heat. Mulch garden beds to retain moisture and suppress weeds.', upsell: 'Mulching' },
  7: { season: 'Summer', tip: 'Water early morning to reduce evaporation. Watch for grub damage -- brown patches that pull up easily.', upsell: 'Lawn Care' },
  8: { season: 'Late Summer', tip: 'Best time for overseeding thin lawns. Core aerate first for best seed-to-soil contact.', upsell: 'Aeration & Overseeding' },
  9: { season: 'Early Fall', tip: 'Fall is the BEST time to fertilize. Cool nights + warm soil = maximum root growth. Aerate and overseed now.', upsell: 'Fall Fertilization' },
  10: { season: 'Fall', tip: 'Keep leaves off your lawn -- they block sunlight and trap moisture. Last mow should be at 2.5 inches.', upsell: 'Fall Cleanup & Leaf Removal' },
  11: { season: 'Late Fall', tip: 'Winterize irrigation systems. Clean gutters before freeze. Apply final winterizer fertilizer.', upsell: 'Gutter Cleaning' },
  12: { season: 'Early Winter', tip: 'Avoid salt damage to lawn edges. Mark sprinkler heads before snow covers them. Rest your lawn.', upsell: 'Snow Removal' }
};

const content = seasonalContent[month];
return [{ json: { monthName, ...content } }];

const items = $input.all();

// Extract month context from first item (comes from merge)
const firstItem = items[0].json;
const monthName = firstItem.monthName || 'This Month';
const season = firstItem.season || '';
const tip = firstItem.tip || '';
const upsell = firstItem.upsell || '';

// Collect reviews and customers from merged data
let reviews = [];
let customers = [];

for (const item of items) {
  const d = item.json;
  if (d.author_name && d.text) {
    reviews.push({ author_name: d.author_name, text: d.text });
  }
  if (d.email && d.id) {
    customers.push({ id: d.id, first_name: d.first_name || 'Neighbor', email: d.email });
  }
}

// Deduplicate customers by email
const seen = new Set();
customers = customers.filter(c => {
  if (seen.has(c.email)) return false;
  seen.add(c.email);
  return true;
});

// Pick a random 5-star review
const review = reviews.length > 0
  ? reviews[Math.floor(Math.random() * reviews.length)]
  : { author_name: 'A Happy Customer', text: 'TotalGuard does an amazing job every time. Highly recommend!' };

const reviewSnippet = review.text.length > 200 ? review.text.substring(0, 200) + '...' : review.text;

const results = [];
for (const c of customers) {
  const name = c.first_name || 'Neighbor';
  const subject = `${monthName} Yard Report from TotalGuard`;
  const previewText = `Your ${monthName} lawn care tips + a special offer inside`;

  const html_body = `<!DOCTYPE html>
<html>
<head>
  <meta charset="utf-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
</head>
<body style="margin:0; padding:0; background-color:#f4f4f4; font-family:Arial, Helvetica, sans-serif;">
  <span style="display:none;font-size:0;color:#f4f4f4;">${previewText}</span>
  <table width="100%" cellpadding="0" cellspacing="0" style="background-color:#f4f4f4; padding:20px 0;">
    <tr>
      <td align="center">
        <table width="600" cellpadding="0" cellspacing="0" style="background-color:#ffffff; border-radius:8px; overflow:hidden;">
          <!-- Header -->
          <tr>
            <td style="background:linear-gradient(135deg, #166534, #15803d); padding:32px 40px; text-align:center;">
              <h1 style="margin:0; color:#ffffff; font-size:24px; font-weight:700;">TotalGuard Yard Care</h1>
              <p style="margin:8px 0 0; color:#bbf7d0; font-size:14px;">${monthName} Yard Report</p>
            </td>
          </tr>
          <!-- Greeting -->
          <tr>
            <td style="padding:32px 40px 16px;">
              <p style="margin:0; font-size:18px; color:#333; font-weight:600;">Hi ${name},</p>
              <p style="margin:12px 0 0; font-size:15px; line-height:1.6; color:#555;">Here's your ${monthName} yard care update with seasonal tips to keep your property looking its best.</p>
            </td>
          </tr>
          <!-- Seasonal Tip -->
          <tr>
            <td style="padding:0 40px 24px;">
              <table width="100%" cellpadding="0" cellspacing="0" style="background-color:#f0fdf4; border-radius:8px; border-left:4px solid #166534;">
                <tr>
                  <td style="padding:20px 24px;">
                    <p style="margin:0 0 4px; font-size:13px; color:#166534; font-weight:700; text-transform:uppercase; letter-spacing:0.5px;">Seasonal Tip: ${season}</p>
                    <p style="margin:0; font-size:15px; line-height:1.6; color:#333;">${tip}</p>
                  </td>
                </tr>
              </table>
            </td>
          </tr>
          <!-- Featured Service -->
          <tr>
            <td style="padding:0 40px 24px;">
              <table width="100%" cellpadding="0" cellspacing="0" style="background-color:#fffbeb; border-radius:8px; border-left:4px solid #d4a017;">
                <tr>
                  <td style="padding:20px 24px;">
                    <p style="margin:0 0 4px; font-size:13px; color:#92400e; font-weight:700; text-transform:uppercase; letter-spacing:0.5px;">Featured This Month</p>
                    <p style="margin:0 0 12px; font-size:15px; line-height:1.6; color:#333;">This is the perfect time for <strong>${upsell}</strong>. Ask us about scheduling -- we have availability this month!</p>
                    <a href="https://tgyardcare.com/contact" target="_blank" style="display:inline-block; background-color:#166534; color:#ffffff; font-size:14px; font-weight:600; text-decoration:none; padding:10px 24px; border-radius:6px;">Book ${upsell}</a>
                  </td>
                </tr>
              </table>
            </td>
          </tr>
          <!-- Review Spotlight -->
          <tr>
            <td style="padding:0 40px 32px;">
              <table width="100%" cellpadding="0" cellspacing="0" style="background-color:#fafafa; border-radius:8px;">
                <tr>
                  <td style="padding:20px 24px;">
                    <p style="margin:0 0 8px; font-size:18px; color:#d4a017;">&#9733;&#9733;&#9733;&#9733;&#9733;</p>
                    <p style="margin:0 0 8px; font-size:14px; line-height:1.6; color:#555; font-style:italic;">&ldquo;${reviewSnippet}&rdquo;</p>
                    <p style="margin:0; font-size:13px; color:#888; font-weight:600;">-- ${review.author_name}</p>
                  </td>
                </tr>
              </table>
            </td>
          </tr>
          <!-- Footer -->
          <tr>
            <td style="background-color:#1a1a2e; padding:24px 40px; text-align:center;">
              <p style="margin:0 0 8px; font-size:14px; color:#a0a0b0;">TotalGuard Yard Care</p>
              <p style="margin:0 0 8px; font-size:14px; color:#a0a0b0;">Madison, WI &bull; (608) 535-6057</p>
              <p style="margin:0; font-size:12px; color:#666680;">You received this because you are a valued TotalGuard customer.</p>
            </td>
          </tr>
        </table>
      </td>
    </tr>
  </table>
</body>
</html>`;

  results.push({
    json: {
      to_email: c.email,
      subject,
      html_body,
      workflow_name: 'TG-81',
      email_type: 'monthly_newsletter'
    }
  });
}

// Store count for telegram summary
if (results.length > 0) {
  results[results.length - 1].json._total_sent = results.length;
  results[results.length - 1].json._monthName = monthName;
  results[results.length - 1].json._upsell = upsell;
}

return results;

